perform:
if (object.properties.worn) {
  return lib.result("You are already wearing the " + lib.ref(object) + ".");
}

return {
  output: "You slip into the silver-gray jumpsuit. It's surprisingly light and seals with a soft magnetic hiss along the front. As you smooth the fabric, you notice a small, unusual lump in the inner lining near the mission patch, but the suit fits perfectly.",
  events: [
    lib.setEvent(object.id, {
      property: "worn",
      value: true,
      description: "Vapor Suit is now worn."
    })
  ]
};

var output = "You run your hands over the silver-gray fabric of the jumpsuit. It's remarkably thin but feels durable. As you check the inner lining near the mission patch, your fingers catch on a small, seamless slit—a hidden pocket.";

if (!store["item:data-chip"]) {
  output += " Inside, you feel the hard edge of a tiny data chip.";
  return {
    output: output,
    events: [
      lib.createEvent("item:data-chip", {
        tags: ["portable"],
        properties: {
          name: "small data chip",
          description: "A fingernail-sized sliver of translucent crystalline material. It catches the light with a faint amber glow.",
          aliases: ["chip", "data chip"],
          location: object.id
        },
        description: "Discovered a data chip in the suit lining"
      })
    ]
  };
}

return lib.result(output + " The hidden pocket is now empty.");

if (!indirect || indirect.id !== 'item:status-panel') {
  return lib.result('You can\'t plug that in there.');
}

return {
  output: 'You slide the translucent sliver into a thin, recessed slot at the base of the Status Panel. The display flickers, the amber glow of the chip bleeding into the screen\'s text. A new menu layer appears: HIBERNATION LOGS - BAY C-1 TO C-12. Most bays show standard signatures, but Bay C-4 shows a manual revival event dated 242 years ago. The occupant is listed as "DEPARTED."',
  events: [
    lib.setEvent(indirect.id, {
      property: 'description',
      value: 'The panel now displays a detailed log overlay from the data chip. Among the rows of green text, one entry in BAY C-4 stands out in bright amber: OCCUPANT REVIVED - 242 YEARS AGO - STATUS: DEPARTED.',
      description: 'Panel updated with chip data'
    }),
    lib.setEvent(object.id, {
      property: 'location',
      value: indirect.id,
      description: 'Chip inserted into panel'
    })
  ]
};

var carried = lib.carried();
var tools = carried.filter(function(e) { return e.tags.has('tool') || e.tags.has('electronic'); });

if (object.properties.systemStatus === 'offline') {
  return lib.result('The panel is dead. Hacking a cold circuit won\'t get you anywhere.');
}

if (tools.length > 0) {
  return {
    output: 'Using the ' + lib.ref(tools[0]) + ', you bypass the security layer. The screen flicker-cycles through hibernation logs for the entire sector. One entry pulses amber: BAY C-4, OCCUPANT REVIVED - 242 YEARS AGO. There is no death certificate on file.',
    events: [lib.setEvent(object.id, { property: 'systemStatus', value: 'operational', description: 'Deep access granted' })]
  };
} else {
  return lib.result('You tap into the maintenance sub-menus with a series of rhythmic presses. The panel resists a full override without proper tools, but you manage to catch a glimpse of a sector map showing an anomalous power draw in Bay C-4.');
}

if (!indirect) {
  return lib.result("What are you aiming at?");
}

var output = "You vigorously crank the handle of the Gurgling Bubble-Thrower. With a series of wet, rhythmic pops, a stream of shimmering, viscous bubbles erupts from the brass bell and drifts toward the " + lib.ref(indirect) + ".";

if (indirect.id === "fixed-display:moss-fountain-inscription") {
  output += " The bubbles stick to the glowing moss, wobbling and reflecting the faint green light like tiny, iridescent lanterns before slowly popping one by one. The moss doesn't seem to mind the bath.";
} else {
  output += " They bounce gently off the surface, wobbling in the air before eventually bursting into small clouds of sweet-smelling vapor.";
}

return lib.result(output);

if (object.id !== 'item:bubble-solution-vial') return { output: `You can't put ${lib.ref(object)} into the thrower.`, events: [] };
if (indirect.id !== 'item:gurgling-bubble-thrower') return { output: `You can only pour the concentrate into the bubble-thrower.`, events: [] };
if (indirect.properties.switchedOn) return { output: 'The thrower is already primed and gurgling.', events: [] };

indirect.properties.switchedOn = true;
return {
  output: `You carefully pour the Joy Concentrate into the reservoir of the bubble-thrower. The device let out a happy gurgle, and a soft blue glow begins to emanate from the nozzle.`,
  events: [
    { type: 'set-property', entityId: indirect.id, property: 'switchedOn', value: true, description: 'Primed the bubble thrower.' },
    { type: 'delete-entity', entityId: object.id, description: 'Empty vial discarded.' }
  ]
};

if (object.id !== 'item:gurgling-bubble-thrower') return { output: `You can't shoot with ${lib.ref(object)}.`, events: [] };
if (indirect.id !== 'item:ornery-service-bot') return { output: 'The bubble-thrower is meant for spreading joy, not random target practice.', events: [] };
if (!object.properties.switchedOn) return { output: 'The bubble-thrower just makes a sad, dry clicking sound. It needs fluid.', events: [] };

const room = store.get('room:the-commons-west');
const exit = store.get('exit:the-commons-west:northwest');

return {
  output: `You crank the handle of the bubble-thrower and aim the trumpet-nozzle at the service-bot. A massive, shimmering blue bubble wobbles out and slowly drifts toward the droid. It lands squarely on the bot's sensor-eye with a wet 'POP!'\n\nThe bot stops humming. It lets out a long, digital sigh that sounds suspiciously like 'Finally...' and begins to perform a slow, rhythmic dance, completely forgetting its duty to block the path. The way to the Weaving District is now clear.`,
  events: [
    { type: 'set-property', entityId: indirect.id, property: 'description', value: 'The service-bot is spinning in happy circles, covered in shimmering soap residue.', description: 'The bot is distracted.' },
    { type: 'set-property', entityId: indirect.id, property: 'name', value: 'Happy Service-Bot', description: 'Renamed the bot.' },
    { type: 'set-property', entityId: 'exit:the-commons-west:northwest', property: 'accessLevel', value: 0, description: 'Path cleared.' }
  ]
};
